#!/usr/bin/env python3
"""
Build surname ground truth corpus from multiple web sources.
Scrapes caste-specific surname lists with URL attribution.

Output: data/surname_ground_truth.csv
Columns: surname, caste, source_url, gothram, region, example_full_names
"""
import csv
import json
import os
import time
from collections import defaultdict

# ─── Ground Truth Data ───────────────────────────────────────────────────────
# Each entry: (caste, source_url, surnames_list, region)
# Surnames are added programmatically from web scraping results

CORPUS = []  # Will be populated below


def add_source(caste, url, surnames_str, region="Krishna-Guntur, AP"):
    """Add a batch of surnames from one source."""
    surnames = [s.strip().upper() for s in surnames_str.split(',') if s.strip()]
    for s in surnames:
        # Skip multi-word entries that aren't surnames
        if len(s) > 30 or ' ' in s.strip():
            continue
        CORPUS.append({
            'surname': s,
            'caste': caste,
            'source_url': url,
            'gothram': '',
            'region': region,
        })


