# KAMMA SOURCES
# ═══════════════════════════════════════════════════════════════════════════

# Source 1: kammaschowdary.blogspot.com (already scraped, 2207 surnames)
# Loaded from our existing match_kamma.py data
kamma_file = os.path.join('archives', 'match_kamma.py')
if os.path.exists(kamma_file):
    with open(kamma_file) as f:
        content = f.read()
    start = content.find('kamma_web_raw = """') + len('kamma_web_raw = """')
    end = content.find('"""', start)
    kamma_raw = content[start:end]
    add_source('Kamma', 'https://kammaschowdary.blogspot.com/p/kammas-surnames-and-gothrams.html',
               ','.join(kamma_raw.split()), 'Andhra Pradesh')

