# ═══════════════════════════════════════════════════════════════════════════
# BUILD AND SAVE
# ═══════════════════════════════════════════════════════════════════════════

def main():
    # Deduplicate: same surname from same source
    seen = set()
    unique = []
    for entry in CORPUS:
        key = (entry['surname'], entry['caste'], entry['source_url'])
        if key not in seen:
            seen.add(key)
            unique.append(entry)

    # Count per caste
    from collections import Counter
    caste_counts = Counter(e['caste'] for e in unique)

    print(f"Ground Truth Corpus Built")
    print(f"{'='*50}")
    print(f"Total unique entries: {len(unique):,}")
    print(f"Unique surnames: {len(set(e['surname'] for e in unique)):,}")
    print(f"\nBy caste:")
    for caste, count in caste_counts.most_common():
        sources = len(set(e['source_url'] for e in unique if e['caste'] == caste))
        print(f"  {caste:<15} {count:>6,} entries from {sources} sources")

    # Find surnames in multiple castes
    surname_castes = defaultdict(set)
    for e in unique:
        surname_castes[e['surname']].add(e['caste'])
    multi = {s: castes for s, castes in surname_castes.items() if len(castes) > 1}
    print(f"\nSurnames appearing in multiple castes: {len(multi)}")
    for s, castes in sorted(multi.items(), key=lambda x: -len(x[1]))[:20]:
        print(f"  {s:<25} {', '.join(sorted(castes))}")

    # Save
    output = os.path.join('data', 'surname_ground_truth.csv')
    with open(output, 'w', newline='', encoding='utf-8') as f:
        writer = csv.writer(f)
        writer.writerow(['surname', 'caste', 'source_url', 'gothram', 'region', 'example_full_names'])
        for e in sorted(unique, key=lambda x: (x['caste'], x['surname'])):
            writer.writerow([e['surname'], e['caste'], e['source_url'], e['gothram'], e['region'], ''])

    print(f"\nSaved to {output}")


if __name__ == '__main__':
    main()
